  1	import type { FC, MouseEvent, ReactNode } from 'react';
  2	
  3	import { ExternalLink } from '@components/common/ExternalLink/ExternalLink';
  4	import {
  5	  Breadcrumb,
  6	  BreadcrumbItem,
  7	  Button,
  8	  ButtonVariant,
  9	  DescriptionListDescription,
 10	  DescriptionListGroup,
 11	  DescriptionListTerm,
 12	  DescriptionListTermHelpText,
 13	  DescriptionListTermHelpTextButton,
 14	  Flex,
 15	  FlexItem,
 16	  Icon,
 17	  Popover,
 18	  Truncate,
 19	} from '@patternfly/react-core';
 20	import { HelpIcon, PencilAltIcon as Pencil } from '@patternfly/react-icons';
 21	import { isEmpty } from '@utils/helpers';
 22	
 23	import { ensureArray } from '../../utils/ensureArray';
 24	
 25	/**
 26	 * Component for displaying title with help text in a popover.
 27	 *
 28	 * @component
 29	 */
 30	const DescriptionTitleWithHelp: FC<{
 31	  title: string;
 32	  helpContent: ReactNode;
 33	  showHelpIconNextToTitle: boolean;
 34	  moreInfoLabel?: string;
 35	  moreInfoLink?: string;
 36	  crumbs?: string[];
 37	}> = ({
 38	  crumbs,
 39	  helpContent,
 40	  moreInfoLabel = 'More info:',
 41	  moreInfoLink,
 42	  showHelpIconNextToTitle = false,
 43	  title,
 44	}) => {
 45	  const onClick: (event: MouseEvent<HTMLButtonElement>) => void = (event) => {
 46	    event.preventDefault();
 47	  };
 48	
 49	  return (
 50	    <DescriptionListTermHelpText className="pf-v6-u-align-items-center">
 51	      {showHelpIconNextToTitle ? <div>{title} &nbsp;</div> : null}
 52	      <Popover
 53	        headerContent={<div>{title}</div>}
 54	        bodyContent={
 55	          <Flex direction={{ default: 'column' }}>
 56	            <FlexItem>{helpContent}</FlexItem>
 57	
 58	            {moreInfoLink && (
 59	              <FlexItem>
 60	                {moreInfoLabel}{' '}
 61	                <ExternalLink href={moreInfoLink} isInline hideIcon>
 62	                  <Truncate content={moreInfoLink} />
 63	                </ExternalLink>
 64	              </FlexItem>
 65	            )}
 66	
 67	            {!isEmpty(crumbs) && (
 68	              <FlexItem>
 69	                <Breadcrumb>
 70	                  {crumbs.map((crumb) => (
 71	                    <BreadcrumbItem key={crumb}>{crumb}</BreadcrumbItem>
 72	                  ))}
 73	                </Breadcrumb>
 74	              </FlexItem>
 75	            )}
 76	          </Flex>
 77	        }
 78	      >
 79	        {showHelpIconNextToTitle ? (
 80	          <Button variant={ButtonVariant.plain} className="pf-v6-u-p-0" onClick={onClick}>
 81	            <Icon size="sm">
 82	              <HelpIcon />
 83	            </Icon>
 84	          </Button>
 85	        ) : (
 86	          <DescriptionListTermHelpTextButton> {title} </DescriptionListTermHelpTextButton>
 87	        )}
 88	      </Popover>
 89	    </DescriptionListTermHelpText>
 90	  );
 91	};
 92	
 93	/**
 94	 * Component for displaying title without a popover.
 95	 *
 96	 * @component
 97	 */
 98	const DescriptionTitle: FC<{ title: string }> = ({ title }) => (
 99	  <DescriptionListTerm> {title} </DescriptionListTerm>
100	);
101	
102	/**
103	 * Component for displaying an item's title
104	 *
105	 * @component
106	 */
107	export const DisplayTitle: FC<{
108	  title: string;
109	  helpContent?: ReactNode;
110	  showHelpIconNextToTitle?: boolean;
111	  moreInfoLabel?: string;
112	  moreInfoLink?: string;
113	  crumbs?: string[];
114	}> = ({
115	  crumbs,
116	  helpContent,
117	  moreInfoLabel,
118	  moreInfoLink,
119	  showHelpIconNextToTitle = false,
120	  title,
121	}) =>
122	  helpContent ? (
123	    <DescriptionTitleWithHelp
124	      title={title}
125	      helpContent={helpContent}
126	      showHelpIconNextToTitle={showHelpIconNextToTitle}
127	      moreInfoLabel={moreInfoLabel}
128	      moreInfoLink={moreInfoLink}
129	      crumbs={crumbs}
130	    />
131	  ) : (
132	    <DescriptionTitle title={title} />
133	  );
134	
135	/**
136	 * Component for displaying an editable or non editable content field with the following format:
137	 * The content field's element and if editable, next to that appears a press-able inline
138	 * link edit button with the pencil icon, for triggering the onEdit callback.
139	 *
140	 * @component
141	 * @param {ReactNode} content - The field's content element.
142	 * @param {Function} onEdit - Function to be called when the button is clicked.
143	 */
144	
145	const ContentField: FC<{
146	  content: ReactNode;
147	  onEdit: () => void;
148	  canEdit?: boolean;
149	}> = ({ canEdit = true, content, onEdit }) =>
150	  canEdit && onEdit ? (
151	    <DescriptionListDescription>
152	      <Flex alignItems={{ default: 'alignItemsCenter' }}>
153	        <FlexItem spacer={{ default: 'spacerNone' }}>{content}</FlexItem>
154	        <FlexItem spacer={{ default: 'spacerNone' }}>
155	          <Button
156	            variant={ButtonVariant.link}
157	            isInline
158	            onClick={onEdit}
159	            icon={<Pencil />}
160	            iconPosition="right"
161	          />
162	        </FlexItem>
163	      </Flex>
164	    </DescriptionListDescription>
165	  ) : (
166	    <DescriptionListDescription>{content}</DescriptionListDescription>
167	  );
168	
169	/**
170	 * Component for displaying a details item.
171	 * It can optionally include a help text popover, breadcrumbs, and an edit button.
172	 *
173	 * @component
174	 * @param {DetailsItemProps} props - The props of the details item.
175	 */
176	
177	/**
178	 * Type for the props of the DetailsItem component.
179	 *
180	 * @typedef {Object} DetailsItemProps
181	 * @property {string} title - The title of the details item.
182	 * @property {ReactNode} [helpContent] - The content to display in the help popover.
183	 * @property {ReactNode} [showHelpIconNextToTitle] - if true, adding a help icon next to the title for displaying the help popover.
184	 *    If false, show the default Patternfly dashed line under the title.
185	 * @property {string[]} [crumbs] - Breadcrumbs for the details item.
186	 * @property {ReactNode | ReactNode[]} content - Array of content fields to be displayed for the details item.
187	 * @property {Function | Function[]} onEdit - Array of functions per content field to be called when the edit button is clicked or null if the field is non editable.
188	 * @property {boolean} [showEditButton] - If true, show the edit button next to the content field, when missing falling back to onEdit existence.
189	 */
190	type DetailsItemProps = {
191	  title: string;
192	  testId?: string;
193	  helpContent?: ReactNode;
194	  showHelpIconNextToTitle?: boolean;
195	  moreInfoLabel?: string;
196	  moreInfoLink?: string;
197	  crumbs?: string[];
198	  content: ReactNode | ReactNode[];
199	  onEdit?: (() => void) | (() => void)[];
200	  canEdit?: boolean;
201	};
202	
203	export const DetailsItem: FC<DetailsItemProps> = ({
204	  canEdit,
205	  content,
206	  crumbs,
207	  helpContent,
208	  moreInfoLabel,
209	  moreInfoLink,
210	  onEdit,
211	  showHelpIconNextToTitle,
212	  testId,
213	  title,
214	}) => {
215	  const contents = ensureArray(content);
216	  const onEdits = ensureArray(onEdit);
217	
218	  return (
219	    <DescriptionListGroup data-testid={testId}>
220	      <DisplayTitle
221	        title={title}
222	        helpContent={helpContent}
223	        showHelpIconNextToTitle={showHelpIconNextToTitle}
224	        moreInfoLabel={moreInfoLabel}
225	        moreInfoLink={moreInfoLink}
226	        crumbs={crumbs}
227	      />
228	      <DescriptionListDescription>
229	        {contents?.map((value, index) => (
230	          <ContentField
231	            key={`content-field-${index}`}
232	            content={value as ReactNode}
233	            onEdit={onEdits?.[index] as () => void}
234	            canEdit={canEdit}
235	          />
236	        ))}
237	      </DescriptionListDescription>
238	    </DescriptionListGroup>
239	  );
240	};

